749	    report.check('…and nothing crashed: the app still serves its data', (await pod.appPage(PROJECT).catch(() => ({ status: 0 }))).status === 200, 'app still 200');
750	
751	    // 3. The guard did not wedge the pipeline: a good one right after STILL works.
752	    const good2 = await pod
753	      .appApi(PROJECT, route, { raw: 'chimney sweep, 38 euro, one off, paid 2026-07-14' }, method)
754	      .catch((e) => ({ status: 0, body: String(e) }));
