786	  const all = hooks.hooks ?? hooks ?? [];
787	  const mine = all.filter((h) => (h.projectId ?? h.project) === PROJECT || !h.projectId);
788	  const flagHook = mine.find((h) => /flag|unusual|anomal|spike|high|alert/i.test(`${h.slug ?? ''} ${h.name ?? ''} ${h.description ?? ''} ${h.on?.event ?? h.event ?? ''}`));
789	  report.check('a "flag unusual bills" automation exists', !!flagHook, flagHook ? JSON.stringify({ slug: flagHook.slug, event: flagHook.on?.event ?? flagHook.event, trigger: flagHook.trigger, hasHandler: flagHook.hasHandler }) : all.map((h) => h.slug).join(', ') || 'no hooks');
