795	    // THE precondition that makes this Act meaningful: the hook LISTENS to the table it WRITES.
796	    // Without the guard that is an infinite loop; with it, it is bounded to one run.
797	    const ev = String(flagHook.on?.event ?? flagHook.event ?? '');
798	    const listensToBills = new RegExp(`db\\.${billsTable}\\.|${billsTable}`, 'i').test(ev);
