801	      listensToBills,
802	      `on.event = ${ev || '(none)'}`,
803	    );
804	
805	    // Deliver one clearly-anomalous bill — ~4× his normal electricity.
806	    const shock = { utility: 'Electricity', provider: 'PPC (DEH)', month: '2026-08', amount: 341.77, due: '2026-09-20' };
807	    await pod.writeFile(
