809	      `type Row = Record<string, unknown>;
810	interface Db { insert(table: string, values: Row): Row }
811	type Ctx = { db: Db };
812	export const name = 'scenarioShockBill';
813	export const description = 'Scenario probe: insert one clearly-anomalous bill to trip the flag automation.';
814	export interface Output { ok: boolean }
815	export default async function handler(input: Row, ctx: Ctx): Promise<Output> {
