822	    const ins = await pod.appApi(PROJECT, '_scenario-shock-bill', shock, 'POST').catch((e) => ({ status: 0, body: String(e) }));
823	    report.check('the anomalous bill (€341.77 — ~4× normal) was inserted', ins.status >= 200 && ins.status < 300, `status ${ins.status}`);
824	
