843	    cp.acts.VI = { passed: report.stepPassed, hook: flagHook.slug, samples };
844	  }
845	  saveCheckpoint(cp);
846	}
847	
848	// ═══ ACT VII — A CODE HOOK COSTS ZERO; AN AGENT HOOK COSTS REAL TOKENS ═════════
849	if (ACTS.includes(7)) {
850	  report.step(
851	    'Act VII — The cheap check stays cheap',
852	    'the overdue check is a pure code handler (hasHandler:true, no trigger) and running it builds ' +
853	      'NO agent session at all (session-ledger unchanged, 0 tokens); the renewal/service scan is an ' +
854	      'agent trigger and running it DOES build one, with nonzero tokens — nobody at the keyboard for either',

