1	/**
2	 * Pod HTTP client — the compute pod IS the app (see sdk/org/libs/cli/src/server/serve.ts).
3	 *
4	 * The pod itself does no auth: Envoy validates the gateway JWT at the edge and routes on the
5	 * `sub` claim to `lmthing.user-<id>.svc`. So every call here just carries the bearer token and
6	 * talks to the chat origin. Locally (`lmthing serve`) pass base=http://localhost:8080 and no token.
7	 */
8	import { LOCAL, restartLocalServer } from './local.mjs';
9	
10	/**
11	 * A pod that is scaling from zero, rolling a new image, or sitting behind a blipping gateway does
12	 * not always answer with a *response* — the connection itself fails (undici's 10s
13	 * `ConnectTimeoutError`, `ECONNRESET`, `socket hang up`, a DNS `EAI_AGAIN`). Those surface as a
14	 * bare `TypeError: fetch failed`, which is NOT an HTTP status and so slipped past every
15	 * `{waking:true}`/504 retry below — one connect timeout to lmthing.chat killed a multi-hour run
16	 * with an uncaught exception. Treat a transient transport fault exactly like a `waking` answer:
17	 * back off and retry. A non-transient error (a bad URL, an aborted body) still throws at once.
18	 */
