  1	/**
  2	 * `<Chat>` — the page-droppable agent chat widget of `@app/runtime`.
  3	 *
  4	 * A page renders `<Chat agent="space/agent" />` and gets the agent's
  5	 * turn-by-turn stream, rendered with the **`@lmthing/ui` catalog descriptor
  6	 * renderer** (`DisplayBlock`/`AskBlock`/`VariablesBlock`) — this is the ONE place
  7	 * that renderer lives inside a page app (pages are otherwise real React; the chat
  8	 * widget is the exception). `ask()` form answers round-trip over the same socket,
  9	 * exactly as `/chat` does.
 10	 *
 11	 * It reuses the standard pod chat protocol wholesale:
 12	 *   1. `POST /api/sessions` `{ spaceRef, projectId }`  →  `{ sessionId }`.
 13	 *   2. `useReplSession({ baseUrl, sessionId })` opens `WS /api/ws?sessionId=<id>`,
 14	 *      streams display/ask/variables/error blocks, and posts user messages +
 15	 *      ask answers back to `/api/sessions/:id/*`.
 16	 *
 17	 * We create the session ourselves (not `ReplRpcClient.createSession`, which posts
 18	 * the `{ spaceDir, agentSlug }` shape) because Phase 7A's endpoint takes
 19	 * `{ spaceRef, projectId }` — but everything downstream (WS, stream decode,
 20	 * ask/message round-trip, descriptor rendering) is reused verbatim from
 21	 * `@lmthing/ui` so the protocol never drifts.
 22	 *
 23	 * Browser/JSX module — bundled by the pages build (excluded from cli tsc). Styled
 24	 * with `@lmthing/css` design tokens only; no raw colors.
 25	 */
 26	import React, { useCallback, useEffect, useRef, useState } from 'react';
 27	import {
 28	  useReplSession,
 29	  DisplayBlock,
 30	  AskBlock,
 31	  VariablesBlock,
 32	  getAccessToken,
 33	  type ReplBlock,
 34	} from '@lmthing/ui/chat';
