 38	/**
 39	 * Platform access token from the same-origin `@lmthing/auth` session (reused via
 40	 * the `@lmthing/ui/chat` barrel — the identical reader the main chat UI uses). On
 41	 * lmthing.app the app page shares localStorage with the launcher, so the OAuth
 42	 * session (set at login) is readable here; the pod's `/api/*` proxy is JWT-gated
 43	 * and 401s an unauthenticated fetch without it. `undefined` in local/no-auth
 44	 * mode (direct pod) — then no token is needed.
 45	 */
 46	function platformAccessToken(): string | undefined {
 47	  try {
 48	    return getAccessToken();
 49	  } catch {
 50	    return undefined;
 51	  }
 52	}
