 56	export interface ChatProps {
 57	  /** The agent to talk to, as a `space/agent` ref (the `spaceRef`). */
 58	  agent: string;
 59	  /** Project scope; defaults to the `…/app/<project>` segment of the URL. */
 60	  projectId?: string;
 61	  /** CSS class for the outer container. */
 62	  className?: string;
 63	}
