 65	/**
 66	 * `<Chat agent="space/agent" />` — drop-in agent chat for a page app.
 67	 */
 68	export function Chat({ agent, projectId, className }: ChatProps): React.ReactElement {
 69	  const [sessionId, setSessionId] = useState<string | null>(null);
 70	  const [error, setError] = useState<string | null>(null);
 71	  const [input, setInput] = useState('');
 72	  // Locally-echoed user turns — the agent stream only carries the agent's own
 73	  // output, so we interleave user messages by recording how many agent blocks
