 75	  const [userMsgs, setUserMsgs] = useState<{ id: string; text: string; afterBlock: number }[]>([]);
 76	  const startedRef = useRef(false);
 77	  const endRef = useRef<HTMLDivElement | null>(null);
 78	
 79	  // Create the session once on mount.
 80	  useEffect(() => {
 81	    if (startedRef.current) return;
 82	    startedRef.current = true;
 83	    void (async () => {
 84	      try {
 85	        const pid = projectId ?? resolveProjectId(window.location.pathname);
 86	        const sid = await createChatSession(agent, pid, originBase(), platformAccessToken());
 87	        setSessionId(sid);
 88	      } catch (err) {
 89	        setError(err instanceof Error ? err.message : String(err));
 90	      }
 91	    })();
 92	    // eslint-disable-next-line react-hooks/exhaustive-deps
 93	  }, []);
 94	
 95	  // Same token for the WS (`&access_token=`) and the `/api/sessions/:id/*` HTTP
 96	  // sub-routes — both flow through the JWT-gated `/api/*` proxy on the platform.
 97	  const accessToken = platformAccessToken();
 98	  const { blocks, sendMessage, submitForm, cancelAsk, isConnected, isDone } = useReplSession(
 99	    sessionId
100	      ? { baseUrl: originBase(), sessionId, accessToken }
101	      : { baseUrl: originBase(), sessionId: '', accessToken },
102	  );
103	
104	  useEffect(() => {
105	    endRef.current?.scrollIntoView({ behavior: 'smooth' });
106	  }, [blocks, userMsgs.length]);
107	
108	  const handleSend = useCallback(() => {
109	    const text = input.trim();
110	    if (!text || !isConnected) return;
111	    setUserMsgs((prev) => [
112	      ...prev,
113	      { id: `u-${Date.now()}-${prev.length}`, text, afterBlock: blocks.length },
114	    ]);
115	    sendMessage(text);
116	    setInput('');
117	  }, [input, isConnected, sendMessage, blocks.length]);
118	
119	  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
120	    if (e.key === 'Enter' && !e.shiftKey) {
121	      e.preventDefault();
122	      handleSend();
123	    }
124	  };
125	
126	  if (error) {
127	    return (
128	      <div style={{ ...styles.container, ...styles.center }} className={className}>
129	        <p style={{ color: 'var(--destructive)', textAlign: 'center', margin: 0 }}>
130	          Failed to start chat: {error}
131	        </p>
132	      </div>
133	    );
134	  }
135	
136	  if (!sessionId) {
137	    return (
138	      <div style={{ ...styles.container, ...styles.center }} className={className}>
139	        <span style={{ color: 'var(--muted-foreground)' }}>Starting agent session…</span>
140	      </div>
141	    );
142	  }
143	
144	  const renderAgentBlock = (block: ReplBlock): React.ReactNode => {
145	    switch (block.type) {
146	      case 'display':
147	        return <DisplayBlock key={block.id} descriptor={block.data} />;
148	      case 'ask':
149	        return (
150	          <AskBlock
151	            key={block.id}
152	            id={block.id}
153	            descriptor={block.data}
154	            onSubmit={submitForm}
155	            onCancel={cancelAsk}
156	          />
157	        );
158	      case 'variables':
159	        return <VariablesBlock key={block.id} vars={block.data as Record<string, unknown>} />;
160	      case 'error':
161	        return (
162	          <div key={block.id} style={styles.errorBlock}>
163	            {String(block.data)}
164	          </div>
165	        );
166	      default:
167	        return null;
168	    }
169	  };
170	
171	  const userBubble = (m: { id: string; text: string }): React.ReactNode => (
172	    <div key={m.id} style={styles.userMsg}>
173	      {m.text}
174	    </div>
175	  );
176	
177	  // Interleave user bubbles with agent blocks by recorded position.
178	  const transcript: React.ReactNode[] = [];
179	  let u = 0;
180	  for (let i = 0; i < blocks.length; i++) {
181	    while (u < userMsgs.length && userMsgs[u]!.afterBlock <= i) transcript.push(userBubble(userMsgs[u++]!));
182	    transcript.push(renderAgentBlock(blocks[i]!));
183	  }
184	  while (u < userMsgs.length) transcript.push(userBubble(userMsgs[u++]!));
185	
186	  return (
187	    <div style={styles.container} className={className}>
188	      <div style={styles.statusBar}>
189	        <span style={{ color: isConnected ? 'var(--success)' : 'var(--destructive)', fontSize: 12 }}>
190	          {isConnected ? '● Connected' : '○ Connecting…'}
191	        </span>
192	        {isDone && (
193	          <span style={{ marginLeft: 12, color: 'var(--muted-foreground)', fontSize: 12 }}>Done</span>
194	        )}
195	      </div>
196	
197	      <div style={styles.blocks}>
198	        {transcript}
199	        <div ref={endRef} />
200	      </div>
201	
202	      <div style={styles.inputRow}>
203	        <textarea
204	          value={input}
205	          onChange={(e) => setInput(e.target.value)}
206	          onKeyDown={handleKeyDown}
207	          placeholder="Message agent… (Enter to send, Shift+Enter for newline)"
208	          disabled={!isConnected}
209	          style={styles.textarea}
210	          rows={2}
211	        />
212	        <button onClick={handleSend} disabled={!isConnected || !input.trim()} style={styles.sendButton}>
213	          Send
214	        </button>
215	      </div>
216	    </div>
217	  );
218	}
