 13	 * {@link serializeHttpError | serializes} it to a plain
 14	 * `{ __httpError, status, message, details }` tag, posts that back, and the main
 15	 * runtime feeds it to {@link errorResponseFor}, which reconstructs the response.
 16	 */
 17	
 18	/** Marker property on the serialized ({@link serializeHttpError}) form. */
 19	const HTTP_ERROR_TAG = '__httpError' as const;
 20	
 21	/**
 22	 * The error an api handler throws to control the HTTP status of its response.
 23	 * `instanceof HttpError` holds inside the handler process; across the worker
 24	 * boundary use {@link serializeHttpError} / {@link isSerializedHttpError}.
 25	 */
 26	export class HttpError extends Error {
 27	  readonly status: number;
 28	  readonly details?: unknown;
 29	
 30	  constructor(status: number, message: string, details?: unknown) {
 31	    super(message);
 32	    this.name = 'HttpError';
 33	    this.status = status;
 34	    this.details = details;
 35	    // Preserve the prototype chain when compiled down to ES5-ish targets.
 36	    Object.setPrototypeOf(this, HttpError.prototype);
 37	  }
 38	}
 39	
 40	/** The wire/body shape every api error response carries. */
 41	export interface ApiErrorBody {
 42	  error: { status: number; message: string; details?: unknown };
 43	}
 44	
 45	/** The `postMessage`-safe plain-object form of an {@link HttpError}. */
 46	export interface SerializedHttpError {
 47	  __httpError: true;
 48	  status: number;
 49	  message: string;
 50	  details?: unknown;
 51	}
 52	
 53	/**
 54	 * Build an {@link ApiErrorBody}. `details` is omitted from the body when
 55	 * `undefined` (so a bare error is `{ error: { status, message } }`).
 56	 */
 57	export function toErrorBody(status: number, message: string, details?: unknown): ApiErrorBody {
 58	  const error: ApiErrorBody['error'] =
 59	    details === undefined ? { status, message } : { status, message, details };
 60	  return { error };
 61	}
 62	
 63	/** Serialize an {@link HttpError} into a structured-clone-safe tagged object. */
 64	export function serializeHttpError(err: HttpError): SerializedHttpError {
 65	  const out: SerializedHttpError = {
 66	    [HTTP_ERROR_TAG]: true,
 67	    status: err.status,
 68	    message: err.message,
 69	  };
 70	  if (err.details !== undefined) out.details = err.details;
 71	  return out;
 72	}
