 91	 *   responsible for logging the real `err`; it is deliberately NOT placed in the
 92	 *   body (never leak internal messages).
 93	 */
 94	export function errorResponseFor(err: unknown): { status: number; body: ApiErrorBody } {
 95	  if (err instanceof HttpError) {
