477:   /** Expand declared relations for each row (belongsTo → object, hasMany → array). */
478:   function expandIncludes(table: string, rows: Row[], include: string[]): void {
479:     const schema = registry.get(table);
480:     if (!schema) {
481:       throw new Error(
482:         `store: query "include" for table "${table}" requires the loaded schemas — pass { schemas } to openProjectDb`,
483:       );
484:     }
485:     for (const relName of include) {
486:       const rel = schema.relations?.[relName];
487:       if (!rel) throw new Error(`store: table "${table}" has no relation "${relName}"`);
488:       if (isBelongsTo(rel)) {
489:         // This table holds the FK (`via`) pointing at one target row.
490:         const targetPk = primaryKeyOf(rel.belongsTo);
491:         for (const row of rows) {
492:           const fk = row[rel.via];
493:           row[relName] =
494:             fk === null || fk === undefined
495:               ? null
496:               : query(rel.belongsTo, { where: { [targetPk]: fk } })[0] ?? null;
497:         }
498:       } else if (isHasMany(rel)) {
499:         // The target table holds the FK (`via`) pointing back at this row's PK.
500:         const thisPk = primaryKeyOf(table);
501:         for (const row of rows) {
502:           row[relName] = query(rel.hasMany, { where: { [rel.via]: row[thisPk] } });
503:         }
504:       }
505:     }
506:   }
