100: function renderRowInterface(table: LoadedTable): string {
101:   const iface = tableInterfaceName(table.name);
102:   const lines: string[] = [];
103:   lines.push(`/** ${table.schema.description} */`);
104:   lines.push(`export interface ${iface} {`);
105: 
106:   for (const [colName, col] of Object.entries(table.schema.columns)) {
107:     const optional = col.primaryKey || col.required ? '' : '?';
108:     lines.push(`  /** ${col.description} */`);
109:     lines.push(`  ${colName}${optional}: ${COLUMN_TS[col.type]};`);
110:   }
111: 
112:   const relations = table.schema.relations ?? {};
113:   for (const [relName, rel] of Object.entries(relations)) {
114:     lines.push(`  /** ${rel.description} */`);
115:     lines.push(`  ${relName}?: ${relationTsType(rel)};`);
116:   }
117: 
118:   lines.push('}');
119:   return lines.join('\n');
120: }
121: 
122: /** TS type for a relation field — `hasMany` → `Target[]`, `belongsTo` → `Target`. */
123: function relationTsType(rel: RelationSchema): string {
124:   if (isHasMany(rel)) return `${tableInterfaceName(rel.hasMany)}[]`;
125:   if (isBelongsTo(rel)) return tableInterfaceName(rel.belongsTo);
126:   return 'unknown';
127: }
